// Format Slack message for traffic alerts
const data = $input.first().json;
const anomalies = data.anomalies || [];

if (anomalies.length === 0) {
  return [{ json: { skip: true } }];
}

// Group by severity
const critical = anomalies.filter(a => a.severity === 'critical');
const warnings = anomalies.filter(a => a.severity === 'warning');
const info = anomalies.filter(a => a.severity === 'info');

// Build message sections
let message = `:chart_with_downwards_trend: *Traffic Anomaly Alert*\n\nDate: ${data.collected_date}\n`;

if (critical.length > 0) {
  message += `\n:red_circle: *Critical* (${critical.length})\n`;
  critical.forEach(a => {
    message += `• ${a.metric}: ${a.current.toLocaleString()} (${a.change_percent}% vs expected ${a.expected.toLocaleString()})\n`;
  });
}

if (warnings.length > 0) {
  message += `\n:large_yellow_circle: *Warning* (${warnings.length})\n`;
  warnings.forEach(a => {
    message += `• ${a.metric}: ${a.current.toLocaleString()} (${a.change_percent}% vs expected ${a.expected.toLocaleString()})\n`;
  });
}

if (info.length > 0) {
  message += `\n:large_blue_circle: *Info* (${info.length})\n`;
  info.forEach(a => {
    message += `• ${a.metric}: ${a.current.toLocaleString()} (+${a.change_percent}% vs expected ${a.expected.toLocaleString()})\n`;
  });
}

message += `\n<https://analytics.google.com|View in GA4>`;

return [{
  json: {
    message,
    severity: critical.length > 0 ? 'critical' : (warnings.length > 0 ? 'warning' : 'info'),
    alert_count: anomalies.length
  }
}];
